            end
            boxStroke.Color = Theme:Border(1)
        end
    end

    updateVisual(value, false)

    card.Active = true
    card.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            value = not value
