    title.TextSize               = 11
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = card

    -- Trigger button
    local trigger = Instance.new("TextButton")
    trigger.BackgroundColor3 = Theme:BG(1)
    trigger.BorderSizePixel  = 0
    trigger.Size             = UDim2.new(1, 0, 0, 28)
    trigger.Text             = ""
    trigger.AutoButtonColor  = false
    trigger.Parent           = card

    local trigCorner = Instance.new("UICorner")
    trigCorner.CornerRadius = UDim.new(0, 6)
    trigCorner.Parent       = trigger

    local trigStroke = Instance.new("UIStroke")
    trigStroke.Color     = Theme:Border(1)
    trigStroke.Thickness = 1
    trigStroke.Parent    = trigger

    local trigPad = Instance.new("UIPadding")
    trigPad.PaddingLeft  = UDim.new(0, 9)
    trigPad.PaddingRight = UDim.new(0, 9)
    trigPad.Parent       = trigger

    local valLbl = Instance.new("TextLabel")
    valLbl.BackgroundTransparency = 1
    valLbl.Size                   = UDim2.new(1, -16, 1, 0)
    valLbl.Text                   = default
    valLbl.Font                   = Enum.Font.Gotham
    valLbl.TextSize               = 11
    valLbl.TextColor3             = Theme:Text(2)
    valLbl.TextXAlignment         = Enum.TextXAlignment.Left
    valLbl.Parent                 = trigger

    local arrow = Instance.new("TextLabel")
    arrow.BackgroundTransparency = 1
    arrow.Size                   = UDim2.fromOffset(12, 28)
    arrow.Position               = UDim2.new(1, -12, 0, 0)
    arrow.Text                   = "▾"
    arrow.Font                   = Enum.Font.Gotham
    arrow.TextSize               = 9
    arrow.TextColor3             = Theme:Text(3)
    arrow.Parent                 = trigger

    -- Dropdown menu
    local menu = Instance.new("Frame")
    menu.BackgroundColor3 = Theme:BG(3)
    menu.BorderSizePixel  = 0
    menu.Size             = UDim2.new(1, 0, 0, 0)
    menu.Position         = UDim2.new(0, 0, 1, 4)
    menu.Visible          = false
    menu.ZIndex           = 50
    menu.ClipsDescendants = true
    menu.Parent           = trigger

    local menuCorner = Instance.new("UICorner")
    menuCorner.CornerRadius = UDim.new(0, 7)
    menuCorner.Parent       = menu

    local menuStroke = Instance.new("UIStroke")
    menuStroke.Color     = Theme:Border(2)
    menuStroke.Thickness = 1
    menuStroke.Parent    = menu

    -- Search bar (only if searchable)
    local searchBox = nil
    if searchable then
        local searchWrap = Instance.new("Frame")
        searchWrap.BackgroundTransparency = 1
        searchWrap.Size                   = UDim2.new(1, 0, 0, 32)
        searchWrap.ZIndex                 = 51
        searchWrap.Parent                 = menu

        local sPad = Instance.new("UIPadding")
        sPad.PaddingLeft   = UDim.new(0, 7)
        sPad.PaddingRight  = UDim.new(0, 7)
        sPad.PaddingTop    = UDim.new(0, 5)
        sPad.PaddingBottom = UDim.new(0, 5)
        sPad.Parent        = searchWrap

        local sBox = Instance.new("TextBox")
        sBox.BackgroundColor3  = Theme:BG(1)
        sBox.BorderSizePixel   = 0
        sBox.Size              = UDim2.new(1, 0, 1, 0)
        sBox.PlaceholderText   = "Search..."
        sBox.PlaceholderColor3 = Theme:Text(4)
        sBox.Text              = ""
        sBox.Font              = Enum.Font.Gotham
        sBox.TextSize          = 11
        sBox.TextColor3        = Theme:Text(0)
        sBox.ClearTextOnFocus  = false
        sBox.ZIndex            = 52
        sBox.Parent            = searchWrap

        local sCorner = Instance.new("UICorner")
        sCorner.CornerRadius = UDim.new(0, 5)
        sCorner.Parent       = sBox

        local sPad2 = Instance.new("UIPadding")
        sPad2.PaddingLeft  = UDim.new(0, 7)
        sPad2.PaddingRight = UDim.new(0, 7)
        sPad2.Parent       = sBox

        local divLine = Instance.new("Frame")
        divLine.BackgroundColor3 = Theme:Border(0)
        divLine.BorderSizePixel  = 0
        divLine.Size             = UDim2.new(1, 0, 0, 1)
        divLine.Position         = UDim2.new(0, 0, 1, 0)
        divLine.Parent           = searchWrap

        searchBox = sBox
    end

    -- Scrollable list
    local list = Instance.new("ScrollingFrame")
    list.BackgroundTransparency  = 1
    list.BorderSizePixel         = 0
    list.Size                    = UDim2.new(1, 0, 1, searchable and -33 or 0)
    list.Position                = UDim2.new(0, 0, 0, searchable and 33 or 0)
    list.CanvasSize              = UDim2.new(0, 0, 0, 0)
    list.AutomaticCanvasSize     = Enum.AutomaticSize.Y
    list.ScrollBarThickness      = 2
    list.ScrollBarImageColor3    = Theme:BG(4)
    list.ZIndex                  = 51
    list.Parent                  = menu

    local listLayout = Instance.new("UIListLayout")
    listLayout.FillDirection = Enum.FillDirection.Vertical
    listLayout.SortOrder     = Enum.SortOrder.LayoutOrder
    listLayout.Parent        = list

    local selected = default
    local allBtns  = {}

    local function buildItems(filter)
        for _, b in ipairs(allBtns) do b:Destroy() end
        allBtns = {}
        local count = 0
        for _, item in ipairs(items) do
            if not filter or item:lower():find(filter:lower(), 1, true) then
                local row = Instance.new("TextButton")
                row.BackgroundTransparency = 1
                row.BorderSizePixel        = 0
                row.Size                   = UDim2.new(1, 0, 0, 30)
                row.Text                   = ""
                row.AutoButtonColor        = false
                row.ZIndex                 = 52
                row.Parent                 = list

                local pad = Instance.new("UIPadding")
                pad.PaddingLeft  = UDim.new(0, 10)
                pad.PaddingRight = UDim.new(0, 10)
                pad.Parent       = row

                local lbl = Instance.new("TextLabel")
                lbl.BackgroundTransparency = 1
                lbl.Size                   = UDim2.new(1, -16, 1, 0)
                lbl.Text                   = item
                lbl.Font                   = Enum.Font.Gotham
                lbl.TextSize               = 11
                lbl.TextColor3             = item == selected and Theme:Accent() or Theme:Text(2)
                lbl.TextXAlignment         = Enum.TextXAlignment.Left
                lbl.ZIndex                 = 53
                lbl.Parent                 = row

                if item == selected then
                    local check = Instance.new("TextLabel")
                    check.BackgroundTransparency = 1
                    check.Size                   = UDim2.fromOffset(12, 30)
                    check.Position               = UDim2.new(1, -12, 0, 0)
                    check.Text                   = "✓"
                    check.TextSize               = 10
                    check.Font                   = Enum.Font.GothamBold
                    check.TextColor3             = Theme:Accent()
                    check.ZIndex                 = 53
                    check.Parent                 = row
                end

                row.MouseEnter:Connect(function()
                    row.BackgroundTransparency = 0
                    Tween.fast(row, { BackgroundColor3 = Theme:BG(4) })
                end)
                row.MouseLeave:Connect(function()
                    Tween.fast(row, { BackgroundColor3 = Theme:BG(3) })
                    row.BackgroundTransparency = 1
                end)

                row.MouseButton1Click:Connect(function()
                    selected    = item
                    valLbl.Text = item
                    if flag then flag:_fire(item) end
                    if opts.Callback then pcall(opts.Callback, item) end
                    closeMenu()
                end)

                table.insert(allBtns, row)
                count = count + 1
            end
        end
        -- Resize menu height (max 5 visible items + search)
        local itemH    = 30
        local maxItems = math.min(count, 6)
        local menuH    = (maxItems * itemH) + (searchable and 33 or 0) + 8
        menu.Size      = UDim2.new(1, 0, 0, menuH)
        list.Size      = UDim2.new(1, 0, 1, searchable and -33 or 0)
    end

    local open = false

    local function openMenu()
        open = true
        buildItems(nil)
        menu.Visible = true
        Tween.fast(arrow, { Rotation = 180 })
        arrow.TextColor3  = Theme:Accent()
        trigStroke.Color  = Theme:Accent()
    end

    function closeMenu()
        open = false
        menu.Visible = false
        Tween.fast(arrow, { Rotation = 0 })
        arrow.TextColor3 = Theme:Text(3)
        trigStroke.Color = Theme:Border(1)
        if searchBox then searchBox.Text = "" end
    end

    trigger.MouseButton1Click:Connect(function()
        if open then closeMenu() else openMenu() end
    end)

    if searchBox then
        searchBox:GetPropertyChangedSignal("Text"):Connect(function()
            buildItems(searchBox.Text ~= "" and searchBox.Text or nil)
        end)
    end

    -- Close on outside click via UserInputService
    game:GetService("UserInputService").InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 and open then
            task.defer(function()
                local pos = game:GetService("UserInputService"):GetMouseLocation()
                local abs  = menu.AbsolutePosition
                local size = menu.AbsoluteSize
                if pos.X < abs.X or pos.X > abs.X + size.X or
                   pos.Y < abs.Y or pos.Y > abs.Y + size.Y then
                    closeMenu()
                end
            end)
        end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    if flag then
        flag:OnChanged(function(v)
            selected    = v
            valLbl.Text = v
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/input/MultiDropdown.lua ─────────────────────
-- MultiDropdown: multi-select dengan tag chips
Section.AddMultiDropdown = function(self, opts)
    assert(type(opts) == "table", "AddMultiDropdown: opts must be a table")
    local items    = opts.Items   or {}
    local defaults = opts.Default or {}
    local flag     = self:_registerFlag(opts.ID, defaults)

    local card, stroke = self:_makeCard()
    card.AutomaticSize    = Enum.AutomaticSize.Y
    card.ClipsDescendants = false

    local col = Instance.new("UIListLayout")
    col.FillDirection = Enum.FillDirection.Vertical
    col.Padding       = UDim.new(0, 5)
    col.Parent        = card

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, 0, 0, 13)
    title.Text                   = opts.Title or ""
    title.Font                   = Enum.Font.Gotham
    title.TextSize               = 11
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = card

    -- Trigger
    local trigger = Instance.new("TextButton")
    trigger.BackgroundColor3 = Theme:BG(1)
    trigger.BorderSizePixel  = 0
    trigger.Size             = UDim2.new(1, 0, 0, 28)
    trigger.AutomaticSize    = Enum.AutomaticSize.Y
    trigger.Text             = ""
    trigger.AutoButtonColor  = false
    trigger.Parent           = card

    local trigCorner = Instance.new("UICorner")
    trigCorner.CornerRadius = UDim.new(0, 6)
    trigCorner.Parent       = trigger

    local trigStroke = Instance.new("UIStroke")
    trigStroke.Color     = Theme:Border(1)
    trigStroke.Thickness = 1
    trigStroke.Parent    = trigger

    local trigPad = Instance.new("UIPadding")
    trigPad.PaddingLeft   = UDim.new(0, 8)
    trigPad.PaddingRight  = UDim.new(0, 24)
    trigPad.PaddingTop    = UDim.new(0, 5)
    trigPad.PaddingBottom = UDim.new(0, 5)
    trigPad.Parent        = trigger

    -- Tags container
    local tagsFrame = Instance.new("Frame")
    tagsFrame.BackgroundTransparency = 1
    tagsFrame.Size                   = UDim2.new(1, 0, 0, 0)
    tagsFrame.AutomaticSize          = Enum.AutomaticSize.Y
    tagsFrame.Parent                 = trigger

    local tagsLayout = Instance.new("UIListLayout")
    tagsLayout.FillDirection        = Enum.FillDirection.Horizontal
    tagsLayout.VerticalAlignment    = Enum.VerticalAlignment.Center
    tagsLayout.Wraps                = true
    tagsLayout.Padding              = UDim.new(0, 3)
    tagsLayout.Parent               = tagsFrame

    local placeholder = Instance.new("TextLabel")
    placeholder.BackgroundTransparency = 1
    placeholder.Size                   = UDim2.new(1, 0, 0, 18)
    placeholder.Text                   = "Select options..."
    placeholder.Font                   = Enum.Font.Gotham
    placeholder.TextSize               = 11
    placeholder.TextColor3             = Theme:Text(4)
    placeholder.TextXAlignment         = Enum.TextXAlignment.Left
    placeholder.Name                   = "Placeholder"
    placeholder.Parent                 = tagsFrame

    local arrow = Instance.new("TextLabel")
    arrow.BackgroundTransparency = 1
    arrow.Size                   = UDim2.fromOffset(12, 18)
    arrow.Position               = UDim2.new(1, -4, 0, 5)
    arrow.Text                   = "▾"
    arrow.Font                   = Enum.Font.Gotham
    arrow.TextSize               = 9
    arrow.TextColor3             = Theme:Text(3)
    arrow.Parent                 = trigger

    -- Dropdown menu
    local menu = Instance.new("ScrollingFrame")
    menu.BackgroundColor3      = Theme:BG(3)
    menu.BorderSizePixel       = 0
    menu.Size                  = UDim2.new(1, 0, 0, 0)
    menu.Position              = UDim2.new(0, 0, 1, 4)
    menu.CanvasSize            = UDim2.new(0, 0, 0, 0)
    menu.AutomaticCanvasSize   = Enum.AutomaticSize.Y
    menu.ScrollBarThickness    = 2
    menu.ScrollBarImageColor3  = Theme:BG(4)
    menu.Visible               = false
    menu.ZIndex                = 50
    menu.ClipsDescendants      = true
    menu.Parent                = trigger

    local menuCorner = Instance.new("UICorner")
    menuCorner.CornerRadius = UDim.new(0, 7)
    menuCorner.Parent       = menu

    local menuStroke = Instance.new("UIStroke")
    menuStroke.Color     = Theme:Border(2)
    menuStroke.Thickness = 1
    menuStroke.Parent    = menu

    local menuLayout = Instance.new("UIListLayout")
    menuLayout.FillDirection = Enum.FillDirection.Vertical
    menuLayout.SortOrder     = Enum.SortOrder.LayoutOrder
    menuLayout.Parent        = menu

    -- State
    local selected = {}
    for _, v in ipairs(defaults) do selected[v] = true end

    local tagObjects = {}

    local function refreshTags()
        -- Clear old tags
        for _, t in pairs(tagObjects) do t:Destroy() end
        tagObjects = {}

        local hasAny = false
        for item, active in pairs(selected) do
            if active then
                hasAny = true
                local tag = Instance.new("Frame")
                tag.BackgroundColor3 = Theme:BG(4)
                tag.BorderSizePixel  = 0
                tag.Size             = UDim2.fromOffset(0, 18)
                tag.AutomaticSize    = Enum.AutomaticSize.X
                tag.Parent           = tagsFrame

                local tagCorner = Instance.new("UICorner")
                tagCorner.CornerRadius = UDim.new(0, 4)
                tagCorner.Parent       = tag

                local tagPad = Instance.new("UIPadding")
                tagPad.PaddingLeft  = UDim.new(0, 5)
                tagPad.PaddingRight = UDim.new(0, 5)
                tagPad.Parent       = tag

                local tagRow = Instance.new("UIListLayout")
                tagRow.FillDirection     = Enum.FillDirection.Horizontal
                tagRow.VerticalAlignment = Enum.VerticalAlignment.Center
                tagRow.Padding           = UDim.new(0, 3)
                tagRow.Parent            = tag

                local tagLbl = Instance.new("TextLabel")
                tagLbl.BackgroundTransparency = 1
                tagLbl.Size                   = UDim2.fromOffset(0, 18)
                tagLbl.AutomaticSize          = Enum.AutomaticSize.X
                tagLbl.Text                   = item
                tagLbl.Font                   = Enum.Font.Gotham
                tagLbl.TextSize               = 9
                tagLbl.TextColor3             = Theme:Accent()
                tagLbl.Parent                 = tag

                local tagX = Instance.new("TextButton")
                tagX.BackgroundTransparency = 1
                tagX.BorderSizePixel        = 0
                tagX.Size                   = UDim2.fromOffset(10, 18)
                tagX.Text                   = "✕"
                tagX.Font                   = Enum.Font.GothamBold
                tagX.TextSize               = 8
                tagX.TextColor3             = Theme:Text(3)
                tagX.Parent                 = tag

                tagX.MouseButton1Click:Connect(function()
                    selected[item] = false
                    refreshTags()
                    local vals = {}
                    for k, v in pairs(selected) do if v then table.insert(vals, k) end end
                    if flag then flag:_fire(vals) end
                    if opts.Callback then pcall(opts.Callback, vals) end
                end)

                table.insert(tagObjects, tag)
            end
        end

        placeholder.Visible = not hasAny
    end

    local function buildMenu()
        for _, child in ipairs(menu:GetChildren()) do
            if child:IsA("TextButton") then child:Destroy() end
        end

        local count = 0
        for _, item in ipairs(items) do
            local row = Instance.new("TextButton")
            row.BackgroundTransparency = 1
            row.BorderSizePixel        = 0
            row.Size                   = UDim2.new(1, 0, 0, 30)
            row.Text                   = ""
            row.AutoButtonColor        = false
            row.ZIndex                 = 52
            row.Parent                 = menu

            local pad = Instance.new("UIPadding")
            pad.PaddingLeft  = UDim.new(0, 10)
            pad.PaddingRight = UDim.new(0, 10)
            pad.Parent       = row

            local check = Instance.new("Frame")
            check.Size             = UDim2.fromOffset(13, 13)
            check.Position         = UDim2.new(0, 0, 0.5, -6)
            check.BackgroundColor3 = selected[item] and Theme:Accent() or Theme:BG(1)
            check.BorderSizePixel  = 0
            check.ZIndex           = 53
            check.Parent           = row

            local checkCorner = Instance.new("UICorner")
            checkCorner.CornerRadius = UDim.new(0, 3)
            checkCorner.Parent       = check

            local checkStroke = Instance.new("UIStroke")
            checkStroke.Color     = selected[item] and Theme:Accent() or Theme:Border(1)
            checkStroke.Thickness = 1
            checkStroke.Parent    = check

            local checkMark = Instance.new("TextLabel")
            checkMark.BackgroundTransparency = 1
            checkMark.Size                   = UDim2.new(1, 0, 1, 0)
            checkMark.Text                   = selected[item] and "✓" or ""
            checkMark.Font                   = Enum.Font.GothamBold
            checkMark.TextSize               = 8
            checkMark.TextColor3             = Color3.new(1, 1, 1)
            checkMark.ZIndex                 = 54
            checkMark.Parent                 = check

            local lbl = Instance.new("TextLabel")
            lbl.BackgroundTransparency = 1
            lbl.Size                   = UDim2.new(1, -22, 1, 0)
            lbl.Position               = UDim2.new(0, 20, 0, 0)
            lbl.Text                   = item
            lbl.Font                   = Enum.Font.Gotham
            lbl.TextSize               = 11
            lbl.TextColor3             = selected[item] and Theme:Accent() or Theme:Text(2)
            lbl.TextXAlignment         = Enum.TextXAlignment.Left
            lbl.ZIndex                 = 53
            lbl.Parent                 = row

            row.MouseEnter:Connect(function()
                Tween.fast(row, { BackgroundColor3 = Theme:BG(4) })
                row.BackgroundTransparency = 0
            end)
            row.MouseLeave:Connect(function()
                row.BackgroundTransparency = 1
            end)

            row.MouseButton1Click:Connect(function()
                selected[item] = not selected[item]
                check.BackgroundColor3 = selected[item] and Theme:Accent() or Theme:BG(1)
                checkStroke.Color      = selected[item] and Theme:Accent() or Theme:Border(1)
                checkMark.Text         = selected[item] and "✓" or ""
                lbl.TextColor3         = selected[item] and Theme:Accent() or Theme:Text(2)
                refreshTags()
                local vals = {}
                for k, v in pairs(selected) do if v then table.insert(vals, k) end end
                if flag then flag:_fire(vals) end
                if opts.Callback then pcall(opts.Callback, vals) end
            end)

            count = count + 1
        end

        local menuH = math.min(count, 6) * 30 + 8
        menu.Size = UDim2.new(1, 0, 0, menuH)
    end

    local open = false

    trigger.MouseButton1Click:Connect(function()
        if open then
            open = false
            menu.Visible     = false
            arrow.TextColor3 = Theme:Text(3)
            trigStroke.Color = Theme:Border(1)
            Tween.fast(arrow, { Rotation = 0 })
        else
            open = true
            buildMenu()
            menu.Visible     = true
            arrow.TextColor3 = Theme:Accent()
            trigStroke.Color = Theme:Accent()
            Tween.fast(arrow, { Rotation = 180 })
        end
    end)

    refreshTags()

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    table.insert(self._components, card)
    return card
end


-- ─── components/input/Keybind.lua ───────────────────────────
-- Keybind: klik lalu tekan key untuk rebind
local UserInputService = game:GetService("UserInputService")

Section.AddKeybind = function(self, opts)
    assert(type(opts) == "table", "AddKeybind: opts must be a table")
    local default = opts.Default or Enum.KeyCode.Unknown
    local flag    = self:_registerFlag(opts.ID, default)

    local card, stroke = self:_makeCard()
    card.AutomaticSize = Enum.AutomaticSize.Y
    card.Size = UDim2.new(1, 0, 0, 0)

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info
    local info = Instance.new("Frame")
    info.BackgroundTransparency = 1
    info.Size                   = UDim2.new(1, -80, 1, 0)
    info.Parent                 = card

    local infoL = Instance.new("UIListLayout")
    infoL.FillDirection     = Enum.FillDirection.Vertical
    infoL.VerticalAlignment = Enum.VerticalAlignment.Center
    infoL.Parent            = info

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, 0, 0, 14)
    title.Text                   = opts.Title or ""
    title.Font                   = Enum.Font.Gotham
    title.TextSize               = 11
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = info

    if opts.Desc then
        local desc = Instance.new("TextLabel")
        desc.BackgroundTransparency = 1
        desc.Size                   = UDim2.new(1, 0, 0, 12)
        desc.Text                   = opts.Desc
        desc.Font                   = Enum.Font.Gotham
        desc.TextSize               = 9
        desc.TextColor3             = Theme:Text(4)
        desc.TextXAlignment         = Enum.TextXAlignment.Left
        desc.Parent                 = info
    end

    -- Key badge button
    local keyBtn = Instance.new("TextButton")
    keyBtn.BackgroundColor3 = Theme:BG(1)
    keyBtn.BorderSizePixel  = 0
    keyBtn.Size             = UDim2.fromOffset(72, 26)
    keyBtn.LayoutOrder      = 99
    keyBtn.AutoButtonColor  = false
    keyBtn.Font             = Enum.Font.GothamBold
    keyBtn.TextSize         = 10
    keyBtn.TextColor3       = Theme:Accent()
    keyBtn.Parent           = card

    local keyCorner = Instance.new("UICorner")
    keyCorner.CornerRadius = UDim.new(0, 5)
    keyCorner.Parent       = keyBtn

    local keyStroke = Instance.new("UIStroke")
    keyStroke.Color     = Theme:Border(1)
    keyStroke.Thickness = 1
    keyStroke.Parent    = keyBtn

    local function keyName(kc)
        if kc == Enum.KeyCode.Unknown then return "NONE" end
        return kc.Name:upper()
    end

    local value    = default
    local listening = false

    keyBtn.Text = keyName(value)

    local function setListening(state)
        listening = state
        if state then
            keyBtn.Text        = "..."
            keyBtn.TextColor3  = Theme:Text(0)
            keyStroke.Color    = Theme:Accent()
            -- pulse animation
            local function pulse()
                if not listening then return end
                Tween.play(keyStroke, { Color = Theme:Accent() },
                    TweenInfo.new(0.4, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut, -1, true))
            end
            pulse()
        else
            keyBtn.Text       = keyName(value)
            keyBtn.TextColor3 = Theme:Accent()
            keyStroke.Color   = Theme:Border(1)
        end
    end

    keyBtn.MouseButton1Click:Connect(function()
        setListening(not listening)
    end)

    UserInputService.InputBegan:Connect(function(input, gpe)
        if not listening then return end
        if input.UserInputType == Enum.UserInputType.Keyboard then
            if input.KeyCode == Enum.KeyCode.Escape then
                setListening(false)
                return
            end
            value = input.KeyCode
            setListening(false)
            if flag then flag:_fire(value) end
            if opts.Callback then pcall(opts.Callback, value) end
        end
    end)

    keyBtn.MouseEnter:Connect(function()
        if not listening then
            Tween.fast(keyBtn, { BackgroundColor3 = Theme:BG(3) })
            keyStroke.Color = Theme:Accent()
        end
    end)
    keyBtn.MouseLeave:Connect(function()
        if not listening then
            Tween.fast(keyBtn, { BackgroundColor3 = Theme:BG(1) })
            keyStroke.Color = Theme:Border(1)
        end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    Theme:OnAccentChanged(function(accent)
        keyBtn.TextColor3 = accent
    end)

    if flag then
        flag:OnChanged(function(v)
            value     = v
            keyBtn.Text = keyName(v)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/input/ColorPicker.lua ───────────────────────
-- ColorPicker: HSV picker dengan hue bar, hex input, dan preset swatches
local UserInputService = game:GetService("UserInputService")

local PRESETS = {
    "#A855F7","#8B5CF6","#6366F1","#3B82F6","#06B6D4",
    "#22C55E","#EAB308","#F97316","#EF4444","#EC4899",
    "#F43F5E","#14B8A6","#FFFFFF","#A1A1AA","#52525B","#27272A",
}

Section.AddColorPicker = function(self, opts)
    assert(type(opts) == "table", "AddColorPicker: opts must be a table")
    local default = opts.Default or Color.fromHex("#A855F7")
    local flag    = self:_registerFlag(opts.ID, default)

    local card, stroke = self:_makeCard()

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info
    local info = Instance.new("Frame")
    info.BackgroundTransparency = 1
    info.Size                   = UDim2.new(1, -42, 1, 0)
    info.Parent                 = card

    local infoL = Instance.new("UIListLayout")
    infoL.FillDirection     = Enum.FillDirection.Vertical
    infoL.VerticalAlignment = Enum.VerticalAlignment.Center
    infoL.Parent            = info

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, 0, 0, 14)
    title.Text                   = opts.Title or ""
    title.Font                   = Enum.Font.Gotham
    title.TextSize               = 11
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = info

    if opts.Desc then
        local desc = Instance.new("TextLabel")
        desc.BackgroundTransparency = 1
        desc.Size                   = UDim2.new(1, 0, 0, 12)
        desc.Text                   = opts.Desc
        desc.Font                   = Enum.Font.Gotham
        desc.TextSize               = 9
        desc.TextColor3             = Theme:Text(4)
        desc.TextXAlignment         = Enum.TextXAlignment.Left
        desc.Parent                 = info
    end

    -- Color preview button
    local previewBtn = Instance.new("TextButton")
    previewBtn.BackgroundColor3 = default
    previewBtn.BorderSizePixel  = 0
    previewBtn.Size             = UDim2.fromOffset(30, 30)
    previewBtn.LayoutOrder      = 99
    previewBtn.Text             = ""
    previewBtn.AutoButtonColor  = false
    previewBtn.Parent           = card

    local pvCorner = Instance.new("UICorner")
    pvCorner.CornerRadius = UDim.new(0, 7)
    pvCorner.Parent       = previewBtn

    local pvStroke = Instance.new("UIStroke")
    pvStroke.Color     = Theme:Border(1)
    pvStroke.Thickness = 2
    pvStroke.Parent    = previewBtn

    -- Palette popup
    local palette = Instance.new("Frame")
    palette.BackgroundColor3 = Theme:BG(3)
    palette.BorderSizePixel  = 0
    palette.Size             = UDim2.fromOffset(220, 0)
    palette.AutomaticSize    = Enum.AutomaticSize.Y
    palette.Position         = UDim2.new(1, 6, 0, 0)
    palette.Visible          = false
    palette.ZIndex           = 60
    palette.Parent           = previewBtn

    local palCorner = Instance.new("UICorner")
    palCorner.CornerRadius = UDim.new(0, 10)
    palCorner.Parent       = palette

    local palStroke = Instance.new("UIStroke")
    palStroke.Color     = Theme:Border(2)
    palStroke.Thickness = 1
    palStroke.Parent    = palette

    local palPad = Instance.new("UIPadding")
    palPad.PaddingLeft   = UDim.new(0, 10)
    palPad.PaddingRight  = UDim.new(0, 10)
    palPad.PaddingTop    = UDim.new(0, 10)
    palPad.PaddingBottom = UDim.new(0, 10)
    palPad.Parent        = palette

    local palCol = Instance.new("UIListLayout")
    palCol.FillDirection = Enum.FillDirection.Vertical
    palCol.Padding       = UDim.new(0, 8)
    palCol.Parent        = palette

    -- ── HUE BAR ─────────────────────────────────────────────
    local hueBar = Instance.new("Frame")
    hueBar.BackgroundColor3 = Color3.new(1, 0, 0)
    hueBar.BorderSizePixel  = 0
    hueBar.Size             = UDim2.new(1, 0, 0, 12)
    hueBar.ZIndex           = 61
    hueBar.Parent           = palette

    -- Gradient across hue
    local hueGrad = Instance.new("UIGradient")
    hueGrad.Color = ColorSequence.new({
        ColorSequenceKeypoint.new(0,   Color3.fromHSV(0,   1, 1)),
        ColorSequenceKeypoint.new(0.17, Color3.fromHSV(0.17,1, 1)),
        ColorSequenceKeypoint.new(0.33, Color3.fromHSV(0.33,1, 1)),
        ColorSequenceKeypoint.new(0.5,  Color3.fromHSV(0.5, 1, 1)),
        ColorSequenceKeypoint.new(0.67, Color3.fromHSV(0.67,1, 1)),
        ColorSequenceKeypoint.new(0.83, Color3.fromHSV(0.83,1, 1)),
        ColorSequenceKeypoint.new(1,   Color3.fromHSV(0,   1, 1)),
    })
    hueGrad.Rotation = 90
    hueGrad.Parent   = hueBar

    local hueCorner = Instance.new("UICorner")
    hueCorner.CornerRadius = UDim.new(1, 0)
    hueCorner.Parent       = hueBar

    local hueThumb = Instance.new("Frame")
    hueThumb.BackgroundColor3 = Color3.new(1, 1, 1)
    hueThumb.BorderSizePixel  = 0
    hueThumb.Size             = UDim2.fromOffset(12, 12)
    hueThumb.Position         = UDim2.new(0, 0, 0, 0)
    hueThumb.ZIndex           = 62
    hueThumb.Parent           = hueBar

    local htCorner = Instance.new("UICorner")
    htCorner.CornerRadius = UDim.new(1, 0)
    htCorner.Parent       = hueThumb

    -- ── HEX INPUT + APPLY ───────────────────────────────────
    local hexRow = Instance.new("Frame")
    hexRow.BackgroundTransparency = 1
    hexRow.Size                   = UDim2.new(1, 0, 0, 26)
    hexRow.ZIndex                 = 61
    hexRow.Parent                 = palette

    local hexRowL = Instance.new("UIListLayout")
    hexRowL.FillDirection     = Enum.FillDirection.Horizontal
    hexRowL.VerticalAlignment = Enum.VerticalAlignment.Center
    hexRowL.Padding           = UDim.new(0, 6)
    hexRowL.Parent            = hexRow

    local hexBox = Instance.new("TextBox")
    hexBox.BackgroundColor3  = Theme:BG(1)
    hexBox.BorderSizePixel   = 0
    hexBox.Size              = UDim2.new(1, -60, 1, 0)
    hexBox.Text              = Color.toHex(default)
    hexBox.PlaceholderText   = "#RRGGBB"
    hexBox.Font              = Enum.Font.Code
    hexBox.TextSize          = 11
    hexBox.TextColor3        = Theme:Text(0)
    hexBox.ClearTextOnFocus  = false
    hexBox.ZIndex            = 62
    hexBox.Parent            = hexRow

    local hexCorner = Instance.new("UICorner")
    hexCorner.CornerRadius = UDim.new(0, 5)
    hexCorner.Parent       = hexBox

    local hexStroke = Instance.new("UIStroke")
    hexStroke.Color     = Theme:Border(1)
    hexStroke.Thickness = 1
    hexStroke.Parent    = hexBox

    local hexPad = Instance.new("UIPadding")
    hexPad.PaddingLeft  = UDim.new(0, 7)
    hexPad.PaddingRight = UDim.new(0, 7)
    hexPad.Parent       = hexBox

    local applyBtn = Instance.new("TextButton")
    applyBtn.BackgroundColor3 = Theme:Accent()
    applyBtn.BorderSizePixel  = 0
    applyBtn.Size             = UDim2.fromOffset(52, 26)
    applyBtn.Text             = "Apply"
    applyBtn.Font             = Enum.Font.GothamBold
    applyBtn.TextSize         = 10
    applyBtn.TextColor3       = Color3.new(1, 1, 1)
    applyBtn.AutoButtonColor  = false
    applyBtn.ZIndex           = 62
    applyBtn.Parent           = hexRow

    local applyCorner = Instance.new("UICorner")
    applyCorner.CornerRadius = UDim.new(0, 5)
    applyCorner.Parent       = applyBtn

    -- ── PRESETS GRID ────────────────────────────────────────
    local presetsGrid = Instance.new("Frame")
    presetsGrid.BackgroundTransparency = 1
    presetsGrid.Size                   = UDim2.new(1, 0, 0, 0)
    presetsGrid.AutomaticSize          = Enum.AutomaticSize.Y
    presetsGrid.ZIndex                 = 61
    presetsGrid.Parent                 = palette

    local presetsLayout = Instance.new("UIGridLayout")
    presetsLayout.CellSize    = UDim2.fromOffset(22, 22)
    presetsLayout.CellPadding = UDim2.fromOffset(4, 4)
    presetsLayout.Parent      = presetsGrid

    for _, hex in ipairs(PRESETS) do
        local sw = Instance.new("TextButton")
        sw.BackgroundColor3 = Color.fromHex(hex)
        sw.BorderSizePixel  = 0
        sw.Size             = UDim2.fromOffset(22, 22)
        sw.Text             = ""
        sw.AutoButtonColor  = false
        sw.ZIndex           = 62
        sw.Parent           = presetsGrid

        local swCorner = Instance.new("UICorner")
        swCorner.CornerRadius = UDim.new(0, 4)
        swCorner.Parent       = sw

        sw.MouseButton1Click:Connect(function()
            hexBox.Text = hex
            local c = Color.fromHex(hex)
            previewBtn.BackgroundColor3 = c
            if flag then flag:_fire(c) end
            if opts.Callback then pcall(opts.Callback, c) end
        end)

        sw.MouseEnter:Connect(function()
            Tween.fast(sw, { Size = UDim2.fromOffset(24, 24) })
        end)
        sw.MouseLeave:Connect(function()
            Tween.fast(sw, { Size = UDim2.fromOffset(22, 22) })
        end)
    end

    -- ── STATE ───────────────────────────────────────────────
    local value    = default
    local hue      = 0
    local dragging = false

    -- Update hue from color
    hue = Color3.toHSV(default)

    local function updateHueThumb(h)
        hueThumb.Position = UDim2.new(h, -6, 0, 0)
    end
    updateHueThumb(hue)

    local function applyHex(hex)
        hex = hex:gsub("#", "")
        if #hex ~= 6 then return end
        local ok, c = pcall(Color.fromHex, "#" .. hex)
        if not ok then return end
        value = c
        previewBtn.BackgroundColor3 = c
        hue = Color3.toHSV(c)
        updateHueThumb(hue)
        if flag then flag:_fire(c) end
        if opts.Callback then pcall(opts.Callback, c) end
    end

    applyBtn.MouseButton1Click:Connect(function()
        applyHex(hexBox.Text)
        palette.Visible = false
    end)

    hexBox.FocusLost:Connect(function(enter)
        if enter then applyHex(hexBox.Text) end
    end)

    -- Hue bar drag
    local hueDragging = false

    hueBar.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            hueDragging = true
        end
    end)

    UserInputService.InputChanged:Connect(function(input)
        if hueDragging and input.UserInputType == Enum.UserInputType.MouseMovement then
            local abs  = hueBar.AbsolutePosition.X
            local size = hueBar.AbsoluteSize.X
            hue = math.clamp((input.Position.X - abs) / size, 0, 1)
            updateHueThumb(hue)
            value = Color3.fromHSV(hue, 1, 1)
            previewBtn.BackgroundColor3 = value
            hexBox.Text = Color.toHex(value)
        end
    end)

    UserInputService.InputEnded:Connect(function(input)
        if hueDragging and input.UserInputType == Enum.UserInputType.MouseButton1 then
            hueDragging = false
            if flag then flag:_fire(value) end
            if opts.Callback then pcall(opts.Callback, value) end
        end
    end)

    -- Toggle palette open/close
    local open = false
    previewBtn.MouseButton1Click:Connect(function()
        open = not open
        palette.Visible = open
        pvStroke.Color  = open and Theme:Accent() or Theme:Border(1)
    end)

    previewBtn.MouseEnter:Connect(function()
        Tween.fast(previewBtn, { Size = UDim2.fromOffset(32, 32) })
        pvStroke.Color = Theme:Accent()
    end)
    previewBtn.MouseLeave:Connect(function()
        Tween.fast(previewBtn, { Size = UDim2.fromOffset(30, 30) })
        if not open then pvStroke.Color = Theme:Border(1) end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    Theme:OnAccentChanged(function(accent)
        applyBtn.BackgroundColor3 = accent
    end)

    if flag then
        flag:OnChanged(function(v)
            value = v
            previewBtn.BackgroundColor3 = v
            hexBox.Text = Color.toHex(v)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/display/Button.lua ──────────────────────────
-- Button: aksi tombol dengan 5 style variant
local STYLES = {
    Default = {
        bg     = function() return Theme:BG(4) end,
        bgHov  = function() return Theme:Accent() end,
        text   = function() return Theme:Accent() end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Theme:Border(1) end,
        borderHov = function() return Theme:Accent() end,
    },
    Danger = {
        bg     = function() return Color.fromHex("#1a0a0a") end,
        bgHov  = function() return Color.fromHex("#ef4444") end,
        text   = function() return Color.fromHex("#f87171") end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Color.fromHex("#3b1010") end,
        borderHov = function() return Color.fromHex("#ef4444") end,
    },
    Success = {
        bg     = function() return Color.fromHex("#0a1a0e") end,
        bgHov  = function() return Color.fromHex("#22c55e") end,
        text   = function() return Color.fromHex("#4ade80") end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Color.fromHex("#0e2e18") end,
        borderHov = function() return Color.fromHex("#22c55e") end,
    },
    Ghost = {
        bg     = function() return Color3.new(0,0,0) end,
        bgHov  = function() return Theme:BG(3) end,
        text   = function() return Theme:Text(3) end,
        textHov= function() return Theme:Text(0) end,
        border = function() return Theme:Border(1) end,
        borderHov = function() return Theme:Border(2) end,
    },
    Warn = {
        bg     = function() return Color.fromHex("#1a1500") end,
        bgHov  = function() return Color.fromHex("#eab308") end,
        text   = function() return Color.fromHex("#fbbf24") end,
        textHov= function() return Color3.new(0,0,0) end,
        border = function() return Color.fromHex("#2e2600") end,
        borderHov = function() return Color.fromHex("#eab308") end,
    },
}

Section.AddButton = function(self, opts)
    assert(type(opts) == "table", "AddButton: opts must be a table")
    local style = STYLES[opts.Style] or STYLES.Default

    local card, _ = self:_makeCard()

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info (optional desc)
    if opts.Desc then
        local info = Instance.new("Frame")
        info.BackgroundTransparency = 1
        info.Size                   = UDim2.new(1, -90, 1, 0)
        info.Parent                 = card

        local infoL = Instance.new("UIListLayout")
        infoL.FillDirection     = Enum.FillDirection.Vertical
        infoL.VerticalAlignment = Enum.VerticalAlignment.Center
        infoL.Parent            = info

        local titleLbl = Instance.new("TextLabel")
        titleLbl.BackgroundTransparency = 1
        titleLbl.Size                   = UDim2.new(1, 0, 0, 14)
        titleLbl.Text                   = opts.Title or ""
        titleLbl.Font                   = Enum.Font.Gotham
        titleLbl.TextSize               = 11
        titleLbl.TextColor3             = Theme:Text(1)
        titleLbl.TextXAlignment         = Enum.TextXAlignment.Left
        titleLbl.Parent                 = info

        local descLbl = Instance.new("TextLabel")
        descLbl.BackgroundTransparency = 1
        descLbl.Size                   = UDim2.new(1, 0, 0, 12)
        descLbl.Text                   = opts.Desc
        descLbl.Font                   = Enum.Font.Gotham
        descLbl.TextSize               = 9
        descLbl.TextColor3             = Theme:Text(4)
        descLbl.TextXAlignment         = Enum.TextXAlignment.Left
        descLbl.Parent                 = info
    end

    -- Button
    local btn = Instance.new("TextButton")
    btn.BackgroundColor3 = style.bg()
    btn.BorderSizePixel  = 0
    btn.Size             = opts.Desc and UDim2.fromOffset(80, 26) or UDim2.new(1, 0, 1, 0)
    btn.Text             = opts.Title or "Button"
    btn.Font             = Enum.Font.GothamBold
    btn.TextSize         = 11
    btn.TextColor3       = style.text()
    btn.AutoButtonColor  = false
    btn.LayoutOrder      = 99
    btn.Parent           = card

    local btnCorner = Instance.new("UICorner")
    btnCorner.CornerRadius = UDim.new(0, 6)
    btnCorner.Parent       = btn

    local btnStroke = Instance.new("UIStroke")
    btnStroke.Color     = style.border()
    btnStroke.Thickness = 1
    btnStroke.Parent    = btn

    btn.MouseEnter:Connect(function()
        Tween.fast(btn, { BackgroundColor3 = style.bgHov() })
        btn.TextColor3 = style.textHov()
        btnStroke.Color = style.borderHov()
    end)
    btn.MouseLeave:Connect(function()
        Tween.fast(btn, { BackgroundColor3 = style.bg() })
        btn.TextColor3 = style.text()
        btnStroke.Color = style.border()
    end)
    btn.MouseButton1Down:Connect(function()
        Tween.fast(btn, { Size = opts.Desc
            and UDim2.fromOffset(78, 24)
            or  UDim2.new(1, -2, 1, -2)
        })
    end)
    btn.MouseButton1Up:Connect(function()
        Tween.fast(btn, { Size = opts.Desc
            and UDim2.fromOffset(80, 26)
            or  UDim2.new(1, 0, 1, 0)
        })
    end)
    btn.MouseButton1Click:Connect(function()
        if opts.Callback then pcall(opts.Callback) end
    end)

    -- Accent update for Default style only
    if not opts.Style or opts.Style == "Default" then
        Theme:OnAccentChanged(function(accent)
            btn.TextColor3  = accent
            btnStroke.Color = Theme:Border(1)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/display/Badge.lua ───────────────────────────
-- Badge: status label inline
local BADGE_COLORS = {
    Purple = { bg = Color.fromHex("#1a0a2e"), text = Color.fromHex("#A855F7"), border = Color.fromHex("#2e1050") },
    Green  = { bg = Color.fromHex("#0a1a0e"), text = Color.fromHex("#22c55e"), border = Color.fromHex("#0e2e18") },
    Red    = { bg = Color.fromHex("#1a0a0a"), text = Color.fromHex("#ef4444"), border = Color.fromHex("#3b1010") },
    Yellow = { bg = Color.fromHex("#1a1500"), text = Color.fromHex("#eab308"), border = Color.fromHex("#2e2600") },
    Blue   = { bg = Color.fromHex("#0a1220"), text = Color.fromHex("#60a5fa"), border = Color.fromHex("#0e1e38") },
}

Section.AddBadge = function(self, opts)
    assert(type(opts) == "table", "AddBadge: opts must be a table")
    local colors = BADGE_COLORS[opts.Color] or BADGE_COLORS.Purple

    local card, stroke = self:_makeCard()
    card.AutomaticSize = Enum.AutomaticSize.Y
    card.Size = UDim2.new(1, 0, 0, 0)

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Title
    local titleLbl = Instance.new("TextLabel")
    titleLbl.BackgroundTransparency = 1
    titleLbl.Size                   = UDim2.new(1, -80, 1, 0)
    titleLbl.Text                   = opts.Title or ""
    titleLbl.Font                   = Enum.Font.Gotham
    titleLbl.TextSize               = 11
    titleLbl.TextColor3             = Theme:Text(1)
    titleLbl.TextXAlignment         = Enum.TextXAlignment.Left
    titleLbl.Parent                 = card

    -- Badge pill
    local badge = Instance.new("Frame")
    badge.BackgroundColor3 = colors.bg
    badge.BorderSizePixel  = 0
    badge.Size             = UDim2.fromOffset(0, 20)
    badge.AutomaticSize    = Enum.AutomaticSize.X
    badge.LayoutOrder      = 99
    badge.Parent           = card

    local badgeCorner = Instance.new("UICorner")
    badgeCorner.CornerRadius = UDim.new(0, 4)
    badgeCorner.Parent       = badge

    local badgeStroke = Instance.new("UIStroke")
    badgeStroke.Color     = colors.border
    badgeStroke.Thickness = 1
    badgeStroke.Parent    = badge

    local badgePad = Instance.new("UIPadding")
    badgePad.PaddingLeft  = UDim.new(0, 7)
    badgePad.PaddingRight = UDim.new(0, 7)
    badgePad.Parent       = badge

    local badgeLbl = Instance.new("TextLabel")
    badgeLbl.BackgroundTransparency = 1
    badgeLbl.Size                   = UDim2.new(1, 0, 1, 0)
    badgeLbl.Text                   = opts.Value or ""
    badgeLbl.Font                   = Enum.Font.GothamBold
    badgeLbl.TextSize               = 9
    badgeLbl.TextColor3             = colors.text
    badgeLbl.Parent                 = badge

    -- Return object with :SetValue()
    local obj = { _badge = badge, _lbl = badgeLbl }
    function obj:SetValue(v)
        badgeLbl.Text = tostring(v)
    end

    table.insert(self._components, card)
    return obj
end


-- ─── components/display/Tag.lua ─────────────────────────────
-- Tag: label yang bisa di-dismiss user
Section.AddTag = function(self, opts)
    assert(type(opts) == "table", "AddTag: opts must be a table")
    local removable = opts.Removable ~= false
    local tags      = {}
    for _, v in ipairs(opts.Tags or {}) do table.insert(tags, v) end

    local card, stroke = self:_makeCard()
    card.AutomaticSize = Enum.AutomaticSize.Y

    local col = Instance.new("UIListLayout")
    col.FillDirection = Enum.FillDirection.Vertical
    col.Padding       = UDim.new(0, 5)
    col.Parent        = card

    if opts.Title then
        local titleLbl = Instance.new("TextLabel")
        titleLbl.BackgroundTransparency = 1
        titleLbl.Size                   = UDim2.new(1, 0, 0, 13)
        titleLbl.Text                   = opts.Title
        titleLbl.Font                   = Enum.Font.Gotham
        titleLbl.TextSize               = 11
        titleLbl.TextColor3             = Theme:Text(1)
        titleLbl.TextXAlignment         = Enum.TextXAlignment.Left
        titleLbl.Parent                 = card
    end

    -- Tags container
    local container = Instance.new("Frame")
    container.BackgroundTransparency = 1
    container.Size                   = UDim2.new(1, 0, 0, 0)
    container.AutomaticSize          = Enum.AutomaticSize.Y
    container.Parent                 = card

    local flowLayout = Instance.new("UIListLayout")
    flowLayout.FillDirection     = Enum.FillDirection.Horizontal
    flowLayout.VerticalAlignment = Enum.VerticalAlignment.Top
    flowLayout.Wraps             = true
    flowLayout.Padding           = UDim.new(0, 5)
    flowLayout.Parent            = container

    local tagObjects = {}

    local function removeTag(tag, tagFrame)
        for i, t in ipairs(tags) do
            if t == tag then table.remove(tags, i) break end
        end
        Tween.fast(tagFrame, { Size = UDim2.fromOffset(0, 22) })
        task.delay(0.15, function() tagFrame:Destroy() end)
        if opts.Callback then pcall(opts.Callback, tags) end
    end

    local function buildTag(tag)
        local frame = Instance.new("Frame")
        frame.BackgroundColor3 = Theme:BG(4)
        frame.BorderSizePixel  = 0
        frame.Size             = UDim2.fromOffset(0, 22)
        frame.AutomaticSize    = Enum.AutomaticSize.X
        frame.Parent           = container

        local fCorner = Instance.new("UICorner")
        fCorner.CornerRadius = UDim.new(0, 20)
        fCorner.Parent       = frame

        local fStroke = Instance.new("UIStroke")
        fStroke.Color     = Theme:Border(1)
        fStroke.Thickness = 1
        fStroke.Parent    = frame

        local fPad = Instance.new("UIPadding")
        fPad.PaddingLeft  = UDim.new(0, 8)
        fPad.PaddingRight = UDim.new(0, removable and 4 or 8)
        fPad.Parent       = frame

        local fRow = Instance.new("UIListLayout")
        fRow.FillDirection     = Enum.FillDirection.Horizontal
        fRow.VerticalAlignment = Enum.VerticalAlignment.Center
        fRow.Padding           = UDim.new(0, 4)
        fRow.Parent            = frame

        local lbl = Instance.new("TextLabel")
        lbl.BackgroundTransparency = 1
        lbl.Size                   = UDim2.fromOffset(0, 22)
        lbl.AutomaticSize          = Enum.AutomaticSize.X
        lbl.Text                   = tag
        lbl.Font                   = Enum.Font.Gotham
        lbl.TextSize               = 10
        lbl.TextColor3             = Theme:Accent()
        lbl.Parent                 = frame

        if removable then
            local xBtn = Instance.new("TextButton")
            xBtn.BackgroundTransparency = 1
            xBtn.BorderSizePixel        = 0
            xBtn.Size                   = UDim2.fromOffset(14, 22)
            xBtn.Text                   = "✕"
            xBtn.Font                   = Enum.Font.GothamBold
            xBtn.TextSize               = 8
            xBtn.TextColor3             = Theme:Text(3)
            xBtn.AutoButtonColor        = false
            xBtn.Parent                 = frame

            xBtn.MouseEnter:Connect(function() xBtn.TextColor3 = Theme:Text(0) end)
            xBtn.MouseLeave:Connect(function() xBtn.TextColor3 = Theme:Text(3) end)
            xBtn.MouseButton1Click:Connect(function() removeTag(tag, frame) end)
        end

        Theme:OnAccentChanged(function(accent) lbl.TextColor3 = accent end)
        table.insert(tagObjects, frame)
        return frame
    end

    for _, tag in ipairs(tags) do buildTag(tag) end

    table.insert(self._components, card)
    return card
end


-- ─── components/display/ProgressBar.lua ─────────────────────
-- ProgressBar: visual indikator 0–100 dengan SetValue
Section.AddProgressBar = function(self, opts)
    assert(type(opts) == "table", "AddProgressBar: opts must be a table")
    local min     = opts.Min   or 0
    local max     = opts.Max   or 100
    local initial = math.clamp(opts.Value or 0, min, max)

    local card, stroke = self:_makeCard()
    card.Size         = UDim2.new(1, 0, 0, 46)
    card.AutomaticSize = Enum.AutomaticSize.None

    -- Title row
    local titleRow = Instance.new("Frame")
    titleRow.BackgroundTransparency = 1
    titleRow.Size                   = UDim2.new(1, 0, 0, 16)
    titleRow.Parent                 = card

    local titleLbl = Instance.new("TextLabel")
    titleLbl.BackgroundTransparency = 1
    titleLbl.Size                   = UDim2.new(1, -40, 1, 0)
    titleLbl.Text                   = opts.Title or ""
    titleLbl.Font                   = Enum.Font.Gotham
    titleLbl.TextSize               = 11
    titleLbl.TextColor3             = Theme:Text(1)
    titleLbl.TextXAlignment         = Enum.TextXAlignment.Left
    titleLbl.Parent                 = titleRow

    local pctLbl = Instance.new("TextLabel")
    pctLbl.BackgroundTransparency = 1
    pctLbl.Size                   = UDim2.fromOffset(40, 16)
    pctLbl.Position               = UDim2.new(1, -40, 0, 0)
    pctLbl.Font                   = Enum.Font.GothamBold
    pctLbl.TextSize               = 11
    pctLbl.TextColor3             = Theme:Accent()
    pctLbl.TextXAlignment         = Enum.TextXAlignment.Right
    pctLbl.Parent                 = titleRow

    -- Track
    local track = Instance.new("Frame")
    track.BackgroundColor3 = Theme:BG(4)
    track.BorderSizePixel  = 0
    track.Size             = UDim2.new(1, 0, 0, 5)
    track.Position         = UDim2.new(0, 0, 0, 24)
    track.Parent           = card

    local trackCorner = Instance.new("UICorner")
    trackCorner.CornerRadius = UDim.new(1, 0)
    trackCorner.Parent       = track

    -- Fill
    local fill = Instance.new("Frame")
    fill.BackgroundColor3 = Theme:Accent()
    fill.BorderSizePixel  = 0
    fill.Size             = UDim2.new(0, 0, 1, 0)
    fill.Parent           = track

    local fillCorner = Instance.new("UICorner")
    fillCorner.CornerRadius = UDim.new(1, 0)
    fillCorner.Parent       = fill

    local fillGrad = Instance.new("UIGradient")
    fillGrad.Color    = ColorSequence.new(Theme:AccentDark(), Theme:Accent())
    fillGrad.Rotation = 90
    fillGrad.Parent   = fill

    local function updateVisual(v, animated)
        local pct = (v - min) / (max - min)
        local pctStr = tostring(math.floor(pct * 100)) .. "%"
        pctLbl.Text = pctStr
        if animated then
            Tween.slow(fill, { Size = UDim2.new(pct, 0, 1, 0) })
        else
            fill.Size = UDim2.new(pct, 0, 1, 0)
        end
    end

    updateVisual(initial, false)

    Theme:OnAccentChanged(function(accent)
        fill.BackgroundColor3 = accent
        pctLbl.TextColor3     = accent
        fillGrad.Color        = ColorSequence.new(Theme:AccentDark(), accent)
    end)

    -- Return object with :SetValue()
    local obj = {}
    function obj:SetValue(v)
        local clamped = math.clamp(v, min, max)
        updateVisual(clamped, true)
    end

    table.insert(self._components, card)
    return obj
end


-- ─── components/display/InfoDisplay.lua ─────────────────────
-- InfoDisplay: key-value rows dengan optional badge
local BADGE_COLORS = {
    Purple = Color.fromHex("#A855F7"),
    Green  = Color.fromHex("#22c55e"),
    Red    = Color.fromHex("#ef4444"),
    Yellow = Color.fromHex("#eab308"),
    Blue   = Color.fromHex("#60a5fa"),
}
local BADGE_BG = {
    Purple = Color.fromHex("#1a0a2e"),
    Green  = Color.fromHex("#0a1a0e"),
    Red    = Color.fromHex("#1a0a0a"),
    Yellow = Color.fromHex("#1a1500"),
    Blue   = Color.fromHex("#0a1220"),
}

Section.AddInfoDisplay = function(self, opts)
    assert(type(opts) == "table", "AddInfoDisplay: opts must be a table")

    local card, stroke = self:_makeCard()
    card.AutomaticSize = Enum.AutomaticSize.Y

    local col = Instance.new("UIListLayout")
    col.FillDirection = Enum.FillDirection.Vertical
    col.Padding       = UDim.new(0, 0)
    col.Parent        = card

    -- Title header
    if opts.Title then
        local hdr = Instance.new("TextLabel")
        hdr.BackgroundTransparency = 1
        hdr.Size                   = UDim2.new(1, 0, 0, 20)
        hdr.Text                   = opts.Title
        hdr.Font                   = Enum.Font.GothamBold
        hdr.TextSize               = 10
        hdr.TextColor3             = Theme:Accent()
        hdr.TextXAlignment         = Enum.TextXAlignment.Left
        hdr.Parent                 = card
        Theme:OnAccentChanged(function(a) hdr.TextColor3 = a end)
    end

    local rowObjects = {}

    local function buildRow(rowOpts, isLast)
        local row = Instance.new("Frame")
        row.BackgroundTransparency = 1
        row.Size                   = UDim2.new(1, 0, 0, 24)
        row.Parent                 = card

        local rowLayout = Instance.new("UIListLayout")
        rowLayout.FillDirection     = Enum.FillDirection.Horizontal
        rowLayout.VerticalAlignment = Enum.VerticalAlignment.Center
        rowLayout.Parent            = row

        -- Bottom divider (not on last row)
        if not isLast then
            local div = Instance.new("Frame")
            div.BackgroundColor3 = Theme:Border(0)
            div.BorderSizePixel  = 0
            div.Size             = UDim2.new(1, 0, 0, 1)
            div.Position         = UDim2.new(0, 0, 1, -1)
            div.Parent           = row
        end

        local keyLbl = Instance.new("TextLabel")
        keyLbl.BackgroundTransparency = 1
        keyLbl.Size                   = UDim2.new(0.45, 0, 1, 0)
        keyLbl.Text                   = rowOpts.Key or ""
        keyLbl.Font                   = Enum.Font.Gotham
        keyLbl.TextSize               = 10
        keyLbl.TextColor3             = Theme:Text(3)
        keyLbl.TextXAlignment         = Enum.TextXAlignment.Left
        keyLbl.Parent                 = row

        -- Value: badge or plain text
        if rowOpts.Badge then
            local badgeColor = BADGE_COLORS[rowOpts.Badge] or BADGE_COLORS.Purple
            local badgeBg    = BADGE_BG[rowOpts.Badge]    or BADGE_BG.Purple

            local badgeFrame = Instance.new("Frame")
            badgeFrame.BackgroundColor3 = badgeBg
            badgeFrame.BorderSizePixel  = 0
            badgeFrame.Size             = UDim2.fromOffset(0, 18)
            badgeFrame.AutomaticSize    = Enum.AutomaticSize.X
            badgeFrame.Parent           = row

            local bCorner = Instance.new("UICorner")
            bCorner.CornerRadius = UDim.new(0, 4)
            bCorner.Parent       = badgeFrame

            local bPad = Instance.new("UIPadding")
            bPad.PaddingLeft  = UDim.new(0, 6)
            bPad.PaddingRight = UDim.new(0, 6)
            bPad.Parent       = badgeFrame

            local bLbl = Instance.new("TextLabel")
            bLbl.BackgroundTransparency = 1
            bLbl.Size                   = UDim2.new(1, 0, 1, 0)
            bLbl.Text                   = rowOpts.Value or ""
            bLbl.Font                   = Enum.Font.GothamBold
            bLbl.TextSize               = 9
            bLbl.TextColor3             = badgeColor
            bLbl.Parent                 = badgeFrame

            rowObjects[rowOpts.Key] = { frame = badgeFrame, lbl = bLbl }
        else
            local valLbl = Instance.new("TextLabel")
            valLbl.BackgroundTransparency = 1
            valLbl.Size                   = UDim2.new(0.55, 0, 1, 0)
            valLbl.Text                   = tostring(rowOpts.Value or "")
            valLbl.Font                   = Enum.Font.Gotham
            valLbl.TextSize               = 10
            valLbl.TextColor3             = Theme:Text(2)
            valLbl.TextXAlignment         = Enum.TextXAlignment.Right
            valLbl.Parent                 = row

            rowObjects[rowOpts.Key] = { lbl = valLbl }
        end

        return row
    end

    local rows = opts.Rows or {}
    for i, rowOpts in ipairs(rows) do
        buildRow(rowOpts, i == #rows)
    end

    -- Return object with :SetRow()
    local obj = {}
    function obj:SetRow(key, value)
        local r = rowObjects[key]
        if r and r.lbl then r.lbl.Text = tostring(value) end
    end

    table.insert(self._components, card)
    return obj
end


